import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { v4 as uuidv4 } from 'uuid';
import { MaintenanceService } from '../../services/maintenance.service';

@Component({
  selector: 'app-maintenance-edit',
  templateUrl: './maintenance-edit.component.html'
})
export class MaintenanceEditComponent implements OnInit {
  form: FormGroup;
  editingId?: string;

  constructor(private fb: FormBuilder, private route: ActivatedRoute, private router: Router, private svc: MaintenanceService) {
    this.form = this.fb.group({
      title: ['', Validators.required],
      description: [''],
      nextDue: [''],
      recurrence: [''],
      assignedTo: [''],
      status: ['pending']
    });
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id && id !== 'new') {
      this.editingId = id;
      this.svc.list$.subscribe(list => {
        const item = list.find(i => i.id === id);
        if (item) this.form.patchValue(item as any);
      });
    }
  }

  save() {
    if (this.form.invalid) return;
    const payload = this.form.value;
    if (this.editingId) {
      this.svc.update(this.editingId, payload);
    } else {
      this.svc.add({ id: uuidv4(), ...payload, createdAt: new Date().toISOString() } as any);
    }
    this.router.navigate(['/maintenance']);
  }
}
<div class="card">
  <h2 *ngIf="editingId; else newTitle">Edit Maintenance</h2>
  <ng-template #newTitle><h2>New Maintenance</h2></ng-template>

  <form [formGroup]="form" (ngSubmit)="save()">
    <div class="form-row">
      <input class="input" placeholder="Title" formControlName="title" required />
      <select class="input" formControlName="status">
        <option value="pending">Pending</option>
        <option value="done">Done</option>
        <option value="skipped">Skipped</option>
      </select>
    </div>
    <div style="margin-top:8px">
      <textarea class="input" placeholder="Description" formControlName="description" rows="3"></textarea>
    </div>
    <div class="form-row" style="margin-top:8px">
      <input class="input" placeholder="Next Due Date" formControlName="nextDue" type="date" />
      <input class="input" placeholder="Recurrence (e.g. monthly, yearly)" formControlName="recurrence" />
    </div>
    <div style="margin-top:8px">
      <input class="input" placeholder="Assigned To" formControlName="assignedTo" />
    </div>

    <div style="margin-top:12px">
      <button class="btn" type="submit">Save</button>
      <a routerLink="/maintenance" style="margin-left:8px">Cancel</a>
    </div>
  </form>
</div>
